qry:select.qry:xquery:
			for $r in sql(' 
 			    SELECT TTA04_HORARIOSPERS.oi_personal_emp, 
 			    TTA02_HORARIOS.e_iniciodia,  
 			    TTA04_HORARIOSPERS.f_fechainicio, 
 			    TTA04_HORARIOSPERS.f_fechafin
					FROM TTA04_HORARIOSPERS, 
					TTA02_HORARIOS, 
					PER02_PERSONAL_EMP, 
					ORG02_ESTRUC_PERS
					JOIN TTA04_HORARIOSPERS.oi_horario INNER TTA02_HORARIOS.oi_horario,
					PER02_PERSONAL_EMP.oi_personal_emp INNER TTA04_HORARIOSPERS.oi_personal_emp,
					PER02_PERSONAL_EMP.oi_personal_emp INNER ORG02_ESTRUC_PERS.oi_personal_emp
					WHERE ORG02_ESTRUC_PERS.oi_clase_org in ({%=string(#ORGANIGRAMAS:CLASES/CLASE/@oi_clase_org)%})
					AND TTA02_HORARIOS.d_tipohorario != \'L\'					
					AND TTA04_HORARIOSPERS.c_estado = \'A\'
					{%? (#FILTRO:@oi_empresa != '') {% AND PER02_PERSONAL_EMP.oi_empresa = {#FILTRO:@oi_empresa} %} {%  %}   %}
					{%? (#FILTRO:@f_des!='') {% AND TTA04_HORARIOSPERS.f_fechainicio > {DateTime(#PARAM:@f_des)} %} {%   %}   %}
					{%? (#FILTRO:@f_has!='') 
						{% AND (TTA04_HORARIOSPERS.f_fechafin < {DateTime(Number(DateTime(#PARAM:@f_des))+1)} 
						OR ISNULL(TTA04_HORARIOSPERS.f_fechafin)) %} 
						{%  %}  
					%}						
					{%? (string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)!='') 
						{% AND ORG02_ESTRUC_PERS.oi_estructura in ({%=string(#FILTRO:ESTRUCTURAS/ESTRUCTURA/@id)%}) %} 
						{%  %} 
					%}
					{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') 
						{% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id)%}) %} 
						{%  %} 
					%}
			')/ROWS/ROW
